class Base {
protected:
    void printValue() const { /*...*/ }
};

class Derived: public Base {
public:
    using Base::printValue;
};

class Base {
public:
    int m_value{};
};

class Derived : public Base {
private:
    using Base::m_value;
};

int main() {
    Derived d{7};
    std::cout &lt;&lt; d.m_value; // OK?
    return 0;
}

class Base {
public:
    int getValue() const { return m_value; }
private:
    int m_value{};
};

class Derived : public Base {
public:
    int getValue() const = delete;
};

int main() {
    Derived d{7};
    std::cout &lt;&lt; d.getValue();
    return 0;
}
